    var ou = gel('alert_account_ou').value;
    var acc = JSON.parse(esAccountId)[ou];
    var eventAccountId = gel('alert_account_id').value;
    if (ou == 'GB') {
        for (var i in acc) {
            var accounts = acc[i];
        }
    }

}

function submitOk() {
    var selectedCase = document.getElementById('selected_case').value;
    if (selectedCase == '') {
        alert("Please Select Case");
        return false;
    }

    var c = gel('cancelled');
    c.value = "false";

    g_form.modified = false;

    return true;
}

function onCancel() {
    GlideDialogWindow.get().destroy();
    return false;
}

sys_ui_page.processing_script:
if (cancelled == "false") {
    createCaseFromEventTask();
}

function createCaseFromEventTask() {

    try {
        var affectedCIs = [];
        var evntAccount = alert_account_id;
        var description = '';
        var worknotes = 'List of Alerts added to the Event Storm:';
        var alertIDs = alert_id;
        var selectedCase = selected_case;
        var getCase = '';

        var alert = new GlideRecord('u_event_task');
        alert.addEncodedQuery('u_event_number.u_account=' + evntAccount + '^u_autoclose_dateISEMPTY^u_has_open_events=true^stateIN1,2^sys_idIN' + alertIDs);
        alert.query();
        var alertIDsArray = alertIDs.split(',');
        var totalSelected = alertIDsArray.length;
        var validCount = alert.getRowCount();
        if (validCount == 0) {
            gs.addErrorMessage("All Alerts initially selected are now closed or ready to be closed. Please refresh the page to select new active Alerts for your Event Storm");
            response.sendRedirect('u_event_task_list.do');
            return;
        }
        gs.addInfoMessage('Only Open Alerts of the list with Open Events will be added to the Event Storm');
        while (alert.next()) {
            description += alert.number + '\n' + '- Configuration Item: ' + alert.u_event_number.u_equipment.getDisplayValue() + '\n' + '- Short Description: ' + alert.short_description + '\n\n';
            worknotes += '\n' + alert.number + ' - ' + alert.short_description;

            if (affectedCIs.indexOf(alert.u_event_number.u_equipment.toString()) == -1) {
                affectedCIs.push(alert.u_event_number.u_equipment.toString());
            }
        }


        var getCaseRecord = new GlideRecord("sn_customerservice_case");
        getCaseRecord.get(selectedCase);
        if (getCaseRecord) {
            getCase = getCaseRecord.getValue('number');
            var currentDescription = getCaseRecord.getValue('description') || '';
            currentDescription += "\n" + description;
            getCaseRecord.setValue('description', currentDescription);
            getCaseRecord.work_notes = worknotes;
            getCaseRecord.update();
        }

        var evntStorm = new GlideRecord('u_event_task');
        evntStorm.addEncodedQuery('sys_idIN' + alertIDs + '^stateIN1,2');
        evntStorm.query();

        while (evntStorm.next()) {
            var grEvent = new GlideRecord('u_event_management');
            grEvent.addEncodedQuery('u_caseISEMPTY^sys_idIN' + evntStorm.u_event_number + '^u_stateIN0,6');
            grEvent.query();

            if (grEvent.next()) {
                grEvent.u_case = selectedCase;
                grEvent.update();
            }
            evntStorm.work_notes = 'The alert has been added to the Event Storm: ' + getCase;
            evntStorm.update();
        }
        // Create affected CI List
        affectedCIs.forEach(function(ci) {
            var grTaskCI = new GlideRecord('task_ci');
            grTaskCI.addQuery('task', selectedCase);
            grTaskCI.addQuery('ci_item', ci);
            grTaskCI.setLimit(1);
            grTaskCI.query();

            if (!grTaskCI.next()) {
                grTaskCI.initialize();
                grTaskCI.task = selectedCase;
                grTaskCI.ci_item = ci;
                grTaskCI.insert();
            }
        });
        response.sendRedirect('sn_customerservice_case.do?sys_id=' + selectedCase);

    } catch (e1) {

    }


}
